use std::collections::HashMap;

struct Memoized<F> {
    func: F,
    cache: HashMap<u64, u64>,
}

impl<F> Memoized<F>
where
    F: Fn(&mut Self, u64) -> u64,
{
    fn new(func: F) -> Self {
        Memoized {
            func,
            cache: HashMap::new(),
        }
    }

    fn call(&mut self, arg: u64) -> u64 {
        if let Some(&result) = self.cache.get(&arg) {
            return result;
        }
        let result = (self.func)(self, arg);
        self.cache.insert(arg, result);
        result
    }
}

fn main() {
    let mut fib = Memoized::new(|memo, n| {
        if n <= 1 {
            n
        } else {
            memo.call(n - 1) + memo.call(n - 2)
        }
    });

    println!("{}", fib.call(40));
}

